import{_ as n,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"27. Superannuation","description":"","frontmatter":{"title":"27. Superannuation","eba":"Nurses and Midwives 2024-2028","topics":["wages","superannuation","preliminary","definitions"]},"headers":[],"relativePath":"ebas/nurses-midwives/wages/27-superannuation.md","filePath":"ebas/nurses-midwives/wages/27-superannuation.md"}'),r={name:"ebas/nurses-midwives/wages/27-superannuation.md"};function i(s,e,p,u,l,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_27-superannuation" tabindex="-1">27. Superannuation <a class="header-anchor" href="#_27-superannuation" aria-label="Permalink to &quot;27. Superannuation&quot;">​</a></h1><p>The subject of superannuation is dealt with extensively by federal legislation which prescribes the obligations and entitlements regarding superannuation. This clause is ancillary to and supplements those provisions.</p><p><strong>27.1</strong> Definitions</p><p>In this clause:</p><p><strong>(a)</strong> default fund means the Aware Super superannuation fund (or its successor) while it provides a &quot;MySuper product&quot; as defined by the Act.</p><p><strong>(b)</strong> preferred superannuation fund means a fund that meets the definition of a superannuation fund in the Superannuation Guarantee (Administration) Act 1992 (Cth).</p><p><strong>27.2</strong> Existing Employees</p><p>Employees will have the choice to nominate that the Employer contributions and their own contributions are made to the Employee&#39;s preferred superannuation fund (as defined above).</p><p><strong>27.3</strong> New Employees</p><p>The Employer will offer to make superannuation contributions on behalf of an Employee to:</p><p><strong>(a)</strong> the Employee&#39;s preferred superannuation fund;</p><p><strong>(b)</strong> HESTA (or successor); or</p><p><strong>(c)</strong> Aware Super superannuation funds (or successor).</p><p><strong>27.4</strong> Where new Employee does not nominate fund</p><p><strong>(a)</strong> The Employer must check with the ATO that the Employee does not have a stapled fund. If the Employee has a stapled fund, the superannuation contribution must be paid to that fund, not the default fund.</p><p><strong>(b)</strong> If the Employee does not nominate a fund, and the ATO does not identify a stapled fund, the Employer will pay the Employee&#39;s superannuation contribution to the default fund.</p><p><strong>27.5</strong> Calculation of superannuation contributions</p><p>Superannuation contributions paid by the Employer will be calculated and paid on:</p><p><strong>(a)</strong> ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Employee&#39;s pre-salary packaging earnings;</p><p><strong>(b)</strong> on and from 1 July 2026, the following additional periods:</p><p><strong>(i)</strong> defence leave;</p><p><strong>(ii)</strong> jury service; and</p><p><strong>(iii)</strong> no safe job leave (whether paid or unpaid);</p><p><strong>(c)</strong> any additional amounts consistent with the trust deed of the superannuation fund; and</p><p><strong>(d)</strong> parental leave (paid and unpaid) in accordance with clause 27.6.</p><p>Note: Superannuation contributions during a period of worker&#39;s compensation leave taken after 1 July 2026 are set out at clause 27.8.</p><p><strong>27.6</strong> Superannuation during parental leave</p><p>The Employer will make superannuation contributions throughout any period of parental leave, paid or unpaid. Except as provided at (c) below, such contributions will be calculated as follows:</p><p><strong>(a)</strong> The Employee&#39;s ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Employee&#39;s pre- salary packaging earnings and any additional amounts consistent with the trust deed of the superannuation fund over 26 full pay periods immediately prior to commencing parental leave and divided by 52 (Weekly Parental Leave Super Contribution), subject to any amendment required by (b)(ii) below;</p><p><strong>(b)</strong> The Weekly Parental Leave Super Contribution will be paid during each week of parental leave (both paid and unpaid) save that:</p><p><strong>(i)</strong> the Employee will receive a pro rata payment for a period less than one (1) week;</p><p><strong>(ii)</strong> where, during the period of parental leave (either paid or unpaid), the Employee&#39;s rate of pay increases under <a href="/eba/ebas/nurses-midwives/wages/25-salary.html">clause 25.2</a>, the Employee&#39;s pre-salary packaging earnings as calculated above will be increased accordingly from the relevant date and superannuation paid on the increased amount; and</p><p><strong>(iii)</strong> Where, during a period of parental leave, the Employer also pays the Employee ordinary time earnings relating to that period, the superannuation contribution will be calculated in accordance with (a) and (b) above, less any superannuation payment made by the Employer in respect of those ordinary time earnings.</p><p><strong>(c)</strong> Information regarding superannuation contributions under this clause 27.6 will be included on a payslip or Employee portal at the same time as it would if the Employee was not on parental leave.</p><p><strong>27.7</strong> Timing of Superannuation contributions</p><p>Superannuation payments will be paid into the Employee&#39;s nominated superannuation account:</p><p><strong>(a)</strong> during the week following wages being paid, or</p><p><strong>(b)</strong> in the case of an Employee on parental leave where there are no wages, the week following the pay period to which the superannuation entitlement relates,</p><p>where this is operationally possible, but not later than would be the case were it a superannuation guarantee payment.</p><p><strong>27.8</strong> Superannuation during worker&#39;s compensation leave</p><p>From 1 July 2026, the Employer will make contributions throughout any period during which a worker is receiving weekly benefits for worker&#39;s compensation (during first 52 weeks of a</p><p>claim). Such contributions will be calculated based on the Employee&#39;s scheme-determined Pre-Injury Average Weekly Earnings (PIAWE).</p><p>Plain language terms: super, employer contribution, SG, retirement fund.</p>',43)])])}const g=n(r,[["render",i]]);export{c as __pageData,g as default};
